// handler.js
const { DynamoDB } = require('@aws-sdk/client-dynamodb');
const { DynamoDBDocument } = require('@aws-sdk/lib-dynamodb');
const crypto = require('crypto');

const client = new DynamoDB({});
const dynamodb = DynamoDBDocument.from(client);

const TABLE_NAME = process.env.USERS_TABLE_NAME;

// Constant-time string comparison to prevent timing attacks
function timingSafeEqual(a, b) {
  if (typeof a !== 'string' || typeof b !== 'string') return false;
  const bufA = Buffer.from(a);
  const bufB = Buffer.from(b);
  if (bufA.length !== bufB.length) {
    // Still do comparison to maintain constant time behavior
    crypto.timingSafeEqual(bufA, Buffer.alloc(bufA.length));
    return false;
  }
  return crypto.timingSafeEqual(bufA, bufB);
}

// Hash password using scrypt (secure, built-in, no external dependencies)
async function hashPassword(password) {
  return new Promise((resolve, reject) => {
    const salt = crypto.randomBytes(32);
    const keyLength = 64;
    const options = { N: 16384, r: 8, p: 1, maxmem: 64 * 1024 * 1024 };

    crypto.scrypt(password, salt, keyLength, options, (err, derivedKey) => {
      if (err) return reject(err);
      const hash = `scrypt:${salt.toString('hex')}:${derivedKey.toString('hex')}:${options.N}:${options.r}:${options.p}`;
      resolve(hash);
    });
  });
}

// Input validation functions
function validateEmail(email) {
  if (typeof email !== 'string') return false;
  // Reasonable length limits
  if (email.length < 3 || email.length > 254) return false;
  // RFC 5322 simplified but strict pattern
  const emailRegex = /^[a-zA-Z0-9.!#$%&'*+/=?^_`{|}~-]+@[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?(?:\.[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?)*$/;
  if (!emailRegex.test(email)) return false;
  // Must have at least one dot in domain
  const domain = email.split('@')[1];
  if (!domain || !domain.includes('.')) return false;
  return true;
}

function validatePassword(password) {
  if (typeof password !== 'string') return false;
  // Minimum 12 characters for strong security, max 128 to prevent DoS via hashing
  if (password.length < 12 || password.length > 128) return false;
  return true;
}

function buildResponse(statusCode, body) {
  return {
    statusCode,
    headers: {
      'Content-Type': 'application/json',
      'Strict-Transport-Security': 'max-age=63072000; includeSubDomains; preload',
      'X-Content-Type-Options': 'nosniff',
      'X-Frame-Options': 'DENY',
      'Cache-Control': 'no-store',
    },
    body: JSON.stringify(body),
  };
}

exports.handler = async (event) => {
  // Only allow POST method
  if (event.httpMethod !== 'POST') {
    return buildResponse(405, { message: 'Method not allowed' });
  }

  // Validate Content-Type
  const contentType = (event.headers?.['Content-Type'] || event.headers?.['content-type'] || '').toLowerCase();
  if (!contentType.includes('application/json')) {
    return buildResponse(415, { message: 'Content-Type must be application/json' });
  }

  // Parse body safely
  let body;
  try {
    body = JSON.parse(event.body || '{}');
  } catch (e) {
    return buildResponse(400, { message: 'Invalid JSON body' });
  }

  // Ensure body is a plain object (not array, not null)
  if (body === null || typeof body !== 'object' || Array.isArray(body)) {
    return buildResponse(400, { message: 'Request body must be a JSON object' });
  }

  const { email, password } = body;

  // Validate email
  if (!validateEmail(email)) {
    return buildResponse(400, {
      message: 'Invalid email address. Must be a valid email format, 3-254 characters.',
    });
  }

  // Validate password
  if (!validatePassword(password)) {
    return buildResponse(400, {
      message: 'Password must be between 12 and 128 characters.',
    });
  }

  // Normalize email to lowercase to prevent duplicate accounts with different casing
  const normalizedEmail = email.toLowerCase().trim();

  try {
    // Hash the password before storing
    const passwordHash = await hashPassword(password);

    const userId = crypto.randomUUID();
    const now = new Date().toISOString();

    // Use a condition expression to prevent overwriting existing accounts
    // This is an atomic check-and-write operation
    await dynamodb.put({
      TableName: TABLE_NAME,
      Item: {
        PK: `USER#${normalizedEmail}`,
        SK: 'PROFILE',
        userId,
        email: normalizedEmail,
        passwordHash,
        createdAt: now,
        updatedAt: now,
        accountStatus: 'ACTIVE',
      },
      ConditionExpression: 'attribute_not_exists(PK)',
    });

    // Do NOT log email, password, or any PII
    console.log(JSON.stringify({
      action: 'user_registration',
      userId,
      timestamp: now,
      status: 'success',
    }));

    return buildResponse(201, {
      message: 'Account created successfully',
      userId,
    });
  } catch (error) {
    if (error.name === 'ConditionalCheckFailedException') {
      // Return generic message to prevent email enumeration
      // Use the same response time pattern regardless of whether account exists
      return buildResponse(409, {
        message: 'Unable to create account. An account with this email may already exist.',
      });
    }

    // Log error without sensitive data
    console.error(JSON.stringify({
      action: 'user_registration',
      status: 'error',
      errorName: error.name,
      errorMessage: error.message,
      // Do NOT log email, password, or request body
    }));

    return buildResponse(500, {
      message: 'An internal error occurred. Please try again later.',
    });
  }
};